import{_ as t,c as n,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Quota-Management: Quota Protection und Smart Warmup | Antigravity-Manager","description":"Lernen Sie das Quota-Management von Antigravity-Manager kennen. Verwenden Sie Quota Protection, um Modelle schwellenwertbasiert zu schützen, Smart Warmup für automatisches Warmup, mit geplanter Überprüfung und Cooldown-Steuerung.","frontmatter":{"title":"Quota-Management: Quota Protection und Smart Warmup | Antigravity-Manager","subtitle":"Quota-Management: Quota Protection und Smart Warmup | Antigravity-Manager","sidebarTitle":"Schützen Sie Ihre Modell-Quoten","description":"Lernen Sie das Quota-Management von Antigravity-Manager kennen. Verwenden Sie Quota Protection, um Modelle schwellenwertbasiert zu schützen, Smart Warmup für automatisches Warmup, mit geplanter Überprüfung und Cooldown-Steuerung.","tags":["quota","warmup","accounts","proxy"],"prerequisite":["start-add-account","start-proxy-and-first-client"],"order":5},"headers":[],"relativePath":"de/lbjlaq/Antigravity-Manager/advanced/quota/index.md","filePath":"de/lbjlaq/Antigravity-Manager/advanced/quota/index.md"}'),a={name:"de/lbjlaq/Antigravity-Manager/advanced/quota/index.md"};function o(s,e,d,l,u,c){return r(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="quota-management-kombinierte-strategie-mit-quota-protection-smart-warmup" tabindex="-1">Quota-Management: Kombinierte Strategie mit Quota Protection + Smart Warmup <a class="header-anchor" href="#quota-management-kombinierte-strategie-mit-quota-protection-smart-warmup" aria-label="Permalink to &quot;Quota-Management: Kombinierte Strategie mit Quota Protection + Smart Warmup&quot;">​</a></h1><p>Sie nutzen Antigravity Tools bereits stabil für Ihre Proxies, aber das größte Problem ist eines: Die Quoten Ihres Hauptmodells werden &quot;leise aufgebraucht&quot;, und wenn Sie es wirklich benötigen, stellen Sie fest, dass sie bereits zu niedrig sind, um effektiv zu arbeiten.</p><p>Diese Lektion konzentriert sich auf das <strong>Quota-Management</strong>: Verwenden Sie Quota Protection, um wichtige Modelle zu erhalten; nutzen Sie Smart Warmup, um ein &quot;leichtes Warmup&quot; durchzuführen, wenn die Quoten wieder voll sind, um temporäre Ausfälle zu reduzieren.</p><h2 id="was-ist-quota-management" tabindex="-1">Was ist Quota-Management? <a class="header-anchor" href="#was-ist-quota-management" aria-label="Permalink to &quot;Was ist Quota-Management?&quot;">​</a></h2><p><strong>Quota-Management</strong> bezeichnet in Antigravity Tools die Verwendung von zwei verknüpften Mechanismen zur Steuerung &quot;wie Quoten ausgegeben werden&quot;: Wenn die verbleibende Quote eines Modells unter einen Schwellenwert fällt, fügt Quota Protection das Modell zu den <code>protected_models</code> des Kontos hinzu; Anfragen an dieses Modell werden bevorzugt umgangen. Wenn die Quote wieder 100% erreicht, löst Smart Warmup eine extrem geringe Traffic-Warmup-Anfrage aus und verwendet eine lokale Verlaufsdatei für einen 4-Stunden-Cooldown.</p><h2 id="was-sie-nach-diesem-kurs-konnen" tabindex="-1">Was Sie nach diesem Kurs können <a class="header-anchor" href="#was-sie-nach-diesem-kurs-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Kurs können&quot;">​</a></h2><ul><li>Aktivieren Sie Quota Protection, damit Konten mit niedrigen Quoten automatisch &quot;ausweichen&quot; und hochwertige Modelle für kritische Anfragen reservieren</li><li>Aktivieren Sie Smart Warmup, damit automatisch ein Warmup durchgeführt wird, wenn die Quoten wieder voll sind (und wissen, wie der 4-Stunden-Cooldown die Auslösefrequenz beeinflusst)</li><li>Verstehen Sie, wo die drei Felder <code>quota_protection</code> / <code>scheduled_warmup</code> / <code>protected_models</code> wirksam werden</li><li>Wissen, welche Modellnamen in &quot;Schutzgruppen&quot; normalisiert werden (und welche nicht)</li></ul><h2 id="ihr-aktuelles-problem" tabindex="-1">Ihr aktuelles Problem <a class="header-anchor" href="#ihr-aktuelles-problem" aria-label="Permalink to &quot;Ihr aktuelles Problem&quot;">​</a></h2><ul><li>Sie denken, Sie &quot;rotieren Konten&quot;, verbrauchen aber tatsächlich kontinuierlich die gleiche Kategorie hochwertiger Modelle</li><li>Sie stellen erst fest, dass die Quoten niedrig sind, wenn es zu spät ist – manchmal verbraucht Claude Code/der Client im Hintergrund Quoten durch Warmup</li><li>Sie haben Warmup aktiviert, wissen aber nicht, wann es genau ausgelöst wird, ob es einen Cooldown gibt und ob es die Quoten beeinflusst</li></ul><h2 id="wann-sie-diese-methode-verwenden" tabindex="-1">Wann Sie diese Methode verwenden <a class="header-anchor" href="#wann-sie-diese-methode-verwenden" aria-label="Permalink to &quot;Wann Sie diese Methode verwenden&quot;">​</a></h2><ul><li>Sie haben mehrere Konten-Pools und möchten sicherstellen, dass kritische Modelle in &quot;wichtigen Momenten&quot; noch Reserven haben</li><li>Sie möchten die Quote-Wiederherstellungszeit nicht manuell überwachen; das System soll automatisch eine &quot;leichte Verifikation nach der Wiederherstellung&quot; durchführen</li></ul><h2 id="🎒-vorbereitungen" tabindex="-1">🎒 Vorbereitungen <a class="header-anchor" href="#🎒-vorbereitungen" aria-label="Permalink to &quot;🎒 Vorbereitungen&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Voraussetzungen</p><p>In dieser Lektion wird vorausgesetzt, dass Sie bereits Folgendes können:</p><ul><li>Auf der <strong>Accounts</strong>-Seite die Kontenliste sehen und Quoten manuell aktualisieren können</li><li>Bereits einen lokalen Reverse-Proxy gestartet haben (mindestens <code>/healthz</code> erreichbar)</li></ul><p>Wenn dies noch nicht funktioniert, lesen Sie zuerst <strong><a href="/docs/opencodedocs/de/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Lokalen Reverse-Proxy starten und ersten Client einbinden</a></strong>.</p></div><p>Außerdem schreibt Smart Warmup eine lokale Verlaufsdatei <code>warmup_history.json</code>. Diese befindet sich im Datenverzeichnis; Position und Backup-Methoden des Datenverzeichnisms finden Sie unter <strong><a href="/docs/opencodedocs/de/lbjlaq/Antigravity-Manager/start/first-run-data/">Erster Start: Datenverzeichnis, Protokolle, Tray und automatischer Start</a></strong>.</p><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>Hinter dieser &quot;kombinierten Strategie&quot; steckt ein sehr einfaches Prinzip:</p><ul><li>Quota Protection sorgt für &quot;keine weitere Verschwendung&quot;: Wenn ein Modell unter den Schwellenwert fällt, wird es als geschützt markiert; Anfragen an dieses Modell werden bevorzugt umgangen (auf Modell-Ebene, nicht pauschal Sperren von Konten).</li><li>Smart Warmup sorgt für &quot;Verifikation bei voller Quote&quot;: Wenn ein Modell wieder 100% erreicht, wird eine leichte Anfrage ausgelöst, um die Verfügbarkeit der Verbindung zu bestätigen; ein 4-Stunden-Cooldown verhindert wiederholte Störungen.</li></ul><p>Die entsprechenden Konfigurationsfelder befinden sich im Frontend in <code>AppConfig</code>:</p><ul><li><code>quota_protection.enabled / threshold_percentage / monitored_models</code> (siehe <code>src/types/config.ts</code>)</li><li><code>scheduled_warmup.enabled / monitored_models</code> (siehe <code>src/types/config.ts</code>)</li></ul><p>Die eigentliche Logik, die entscheidet, &quot;ob das Konto bei Anfragen an dieses Modell übersprungen werden soll&quot;, befindet sich im Backend in TokenManager:</p><ul><li>Das Feld <code>protected_models</code> in der Kontodatei wird in <code>get_token(..., target_model)</code> bei der Filterung berücksichtigt (siehe <code>src-tauri/src/proxy/token_manager.rs</code>)</li><li><code>target_model</code> wird zuerst normalisiert (<code>normalize_to_standard_id</code>), sodass Varianten wie <code>claude-sonnet-4-5-thinking</code> in dieselbe &quot;Schutzgruppe&quot; zusammengefasst werden (siehe <code>src-tauri/src/proxy/common/model_mapping.rs</code>)</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="/docs/opencodedocs/de/lbjlaq/Antigravity-Manager/advanced/monitoring/">Proxy Monitor: Anfrageprotokolle, Filter, Detail-Rekonstruktion und Export</a></strong>, um die Blackbox-Aufrufe in eine rekonstruierbare Beweiskette zu verwandeln.</p></blockquote><h2 id="machen-sie-mit" tabindex="-1">Machen Sie mit <a class="header-anchor" href="#machen-sie-mit" aria-label="Permalink to &quot;Machen Sie mit&quot;">​</a></h2><h3 id="schritt-1-bringen-sie-die-quoten-zuerst-auf-den-aktuellen-stand" tabindex="-1">Schritt 1: Bringen Sie die Quoten zuerst &quot;auf den aktuellen Stand&quot; <a class="header-anchor" href="#schritt-1-bringen-sie-die-quoten-zuerst-auf-den-aktuellen-stand" aria-label="Permalink to &quot;Schritt 1: Bringen Sie die Quoten zuerst &quot;auf den aktuellen Stand&quot;&quot;">​</a></h3><p><strong>Warum</strong> Quota Protection basiert auf dem <code>quota.models[].percentage</code> des Kontos. Ohne aktualisierte Quoten kann die Schutzlogik nichts für Sie tun.</p><p>Vorgehensweise: Öffnen Sie die <strong>Accounts</strong>-Seite und klicken Sie auf die Aktualisierungsschaltfläche in der Symbolleiste (entweder für ein einzelnes Konto oder alle).</p><p><strong>Was Sie sehen sollten</strong>: In der Kontozeile erscheinen die Quoten-Prozentsätze der einzelnen Modelle (z. B. 0-100) und die Reset-Zeit.</p><h3 id="schritt-2-aktivieren-sie-in-den-einstellungen-smart-warmup-optional-aber-empfohlen" tabindex="-1">Schritt 2: Aktivieren Sie in den Einstellungen Smart Warmup (optional, aber empfohlen) <a class="header-anchor" href="#schritt-2-aktivieren-sie-in-den-einstellungen-smart-warmup-optional-aber-empfohlen" aria-label="Permalink to &quot;Schritt 2: Aktivieren Sie in den Einstellungen Smart Warmup (optional, aber empfohlen)&quot;">​</a></h3><p><strong>Warum</strong> Das Ziel von Smart Warmup ist nicht &quot;Quoten sparen&quot;, sondern &quot;Verbindung bei voller Quote selbst prüfen&quot;. Es wird nur ausgelöst, wenn die Modellquote 100% erreicht, und hat einen 4-Stunden-Cooldown.</p><p>Vorgehensweise: Öffnen Sie <strong>Settings</strong>, wechseln Sie zum Bereich für Kontoeinstellungen, aktivieren Sie den <strong>Smart Warmup</strong>-Schalter und wählen Sie die Modelle aus, die Sie überwachen möchten.</p><p>Vergessen Sie nicht, die Einstellungen zu speichern.</p><p><strong>Was Sie sehen sollten</strong>: Nach dem Aufklappen von Smart Warmup erscheint eine Modellliste; mindestens ein Modell muss ausgewählt bleiben.</p><h3 id="schritt-3-aktivieren-sie-quota-protection-und-legen-sie-schwellenwert-und-uberwachte-modelle-fest" tabindex="-1">Schritt 3: Aktivieren Sie Quota Protection und legen Sie Schwellenwert und überwachte Modelle fest <a class="header-anchor" href="#schritt-3-aktivieren-sie-quota-protection-und-legen-sie-schwellenwert-und-uberwachte-modelle-fest" aria-label="Permalink to &quot;Schritt 3: Aktivieren Sie Quota Protection und legen Sie Schwellenwert und überwachte Modelle fest&quot;">​</a></h3><p><strong>Warum</strong> Quota Protection ist der Kern der &quot;Reservenhaltung&quot;: Wenn der Quoten-Prozentsatz der überwachten Modelle <code>&lt;= threshold_percentage</code> ist, wird das Modell in die <code>protected_models</code>-Felder der Kontodatei geschrieben; spätere Anfragen an dieses Modell bevorzugen das Umgehen solcher Konten.</p><p>Vorgehensweise: Aktivieren Sie in <strong>Settings</strong> die Option <strong>Quota Protection</strong>.</p><ol><li>Legen Sie den Schwellenwert fest (<code>1-99</code>)</li><li>Wählen Sie die Modelle aus, die Sie überwachen möchten (mindestens eines)</li></ol><div class="tip custom-block"><p class="custom-block-title">Ein sehr nützlicher Startwert</p><p>Wenn Sie sich nicht festlegen möchten, können Sie beim Standard <code>threshold_percentage=10</code> beginnen (siehe <code>src/pages/Settings.tsx</code>).</p></div><p><strong>Was Sie sehen sollten</strong>: Mindestens ein Modell muss in der Quota Protection-Auswahl ausgewählt bleiben (die UI verhindert, dass Sie auch das letzte abwählen).</p><h3 id="schritt-4-bestatigen-sie-dass-die-schutzgruppen-normalisierung-sie-nicht-vor-probleme-stellt" tabindex="-1">Schritt 4: Bestätigen Sie, dass die &quot;Schutzgruppen-Normalisierung&quot; Sie nicht vor Probleme stellt <a class="header-anchor" href="#schritt-4-bestatigen-sie-dass-die-schutzgruppen-normalisierung-sie-nicht-vor-probleme-stellt" aria-label="Permalink to &quot;Schritt 4: Bestätigen Sie, dass die &quot;Schutzgruppen-Normalisierung&quot; Sie nicht vor Probleme stellt&quot;">​</a></h3><p><strong>Warum</strong> Bei der Quota-Schutzentscheidung normalisiert TokenManager zuerst <code>target_model</code> zu einer Standard-ID (<code>normalize_to_standard_id</code>). Beispielsweise wird <code>claude-sonnet-4-5-thinking</code> zu <code>claude-sonnet-4-5</code> normalisiert.</p><p>Das bedeutet:</p><ul><li>Sie wählen <code>claude-sonnet-4-5</code> in Quota Protection aus</li><li>Wenn Sie tatsächlich <code>claude-sonnet-4-5-thinking</code> anfordern</li></ul><p>wird dennoch der Schutz ausgelöst (da sie zur gleichen Gruppe gehören).</p><p><strong>Was Sie sehen sollten</strong>: Wenn die <code>protected_models</code> eines Kontos <code>claude-sonnet-4-5</code> enthalten, werden Anfragen an <code>claude-sonnet-4-5-thinking</code> dieses Konto bevorzugt umgehen.</p><h3 id="schritt-5-verwenden-sie-manuelles-warmup-um-sofort-zu-verifizieren" tabindex="-1">Schritt 5: Verwenden Sie &quot;manuelles Warmup&quot;, um sofort zu verifizieren <a class="header-anchor" href="#schritt-5-verwenden-sie-manuelles-warmup-um-sofort-zu-verifizieren" aria-label="Permalink to &quot;Schritt 5: Verwenden Sie &quot;manuelles Warmup&quot;, um sofort zu verifizieren&quot;">​</a></h3><p><strong>Warum</strong> Der Scan-Zyklus für geplantes Smart Warmup beträgt 10 Minuten (siehe <code>src-tauri/src/modules/scheduler.rs</code>). Wenn Sie die Verbindung sofort verifizieren möchten, ist manuelles Warmup direkter.</p><p>Vorgehensweise: Öffnen Sie die <strong>Accounts</strong>-Seite und klicken Sie auf die &quot;Warmup&quot;-Schaltfläche in der Symbolleiste:</p><ul><li>Ohne Kontoauswahl: Löst vollständiges Warmup aus (ruft <code>warm_up_all_accounts</code> auf)</li><li>Mit ausgewählten Konten: Löst Warmup für die ausgewählten Konten einzeln aus (ruft <code>warm_up_account</code> auf)</li></ul><p><strong>Was Sie sehen sollten</strong>: Ein Toast erscheint, dessen Inhalt aus dem vom Backend zurückgegebenen String stammt (z. B. &quot;Warmup task triggered ...&quot;).</p><h2 id="kontrollpunkte-✅" tabindex="-1">Kontrollpunkte ✅ <a class="header-anchor" href="#kontrollpunkte-✅" aria-label="Permalink to &quot;Kontrollpunkte ✅&quot;">​</a></h2><ul><li>Sie können auf der Accounts-Seite den Quoten-Prozentsatz der einzelnen Modelle jedes Kontos sehen (beweist, dass die Quoten-Datenpipeline funktioniert)</li><li>Sie können in Settings Quota Protection / Smart Warmup aktivieren und die Konfiguration erfolgreich speichern</li><li>Sie verstehen, dass <code>protected_models</code> eine &quot;Modell-Ebene&quot;-Beschränkung ist: Ein Konto kann möglicherweise nur für bestimmte Modelle umgangen werden</li><li>Sie wissen, dass Warmup einen 4-Stunden-Cooldown hat: Kurzfristig wiederholtes Klicken auf Warmup kann möglicherweise Hinweise wie &quot;skipped/cooldown&quot; anzeigen</li></ul><h2 id="warnungen-vor-stolpersteinen" tabindex="-1">Warnungen vor Stolpersteinen <a class="header-anchor" href="#warnungen-vor-stolpersteinen" aria-label="Permalink to &quot;Warnungen vor Stolpersteinen&quot;">​</a></h2><h3 id="_1-sie-haben-quota-protection-aktiviert-aber-es-wirkt-nie" tabindex="-1">1) Sie haben Quota Protection aktiviert, aber es wirkt nie <a class="header-anchor" href="#_1-sie-haben-quota-protection-aktiviert-aber-es-wirkt-nie" aria-label="Permalink to &quot;1) Sie haben Quota Protection aktiviert, aber es wirkt nie&quot;">​</a></h3><p>Der häufigste Grund ist: Das Konto hat keine <code>quota</code>-Daten. Die Schutzlogik muss im Backend zuerst <code>quota.models[]</code> lesen, um den Schwellenwert beurteilen zu können (siehe <code>src-tauri/src/proxy/token_manager.rs</code>).</p><p>Sie können zu <strong>Schritt 1</strong> zurückkehren und die Quoten zuerst aktualisieren.</p><h3 id="_2-warum-werden-nur-wenige-modelle-als-schutzgruppe-behandelt" tabindex="-1">2) Warum werden nur wenige Modelle als &quot;Schutzgruppe&quot; behandelt? <a class="header-anchor" href="#_2-warum-werden-nur-wenige-modelle-als-schutzgruppe-behandelt" aria-label="Permalink to &quot;2) Warum werden nur wenige Modelle als &quot;Schutzgruppe&quot; behandelt?&quot;">​</a></h3><p>Die Normalisierung von <code>target_model</code> durch TokenManager erfolgt &quot;auf Whitelist-Basis&quot;: Nur explizit aufgelistete Modellnamen werden einer Standard-ID zugeordnet (siehe <code>src-tauri/src/proxy/common/model_mapping.rs</code>).</p><p>Die Logik nach der Normalisierung lautet: Der normalisierte Name (Standard-ID oder ursprünglicher Modellname) wird mit dem <code>protected_models</code>-Feld des Kontos abgeglichen. Wenn die Übereinstimmung erfolgreich ist, wird das Konto übersprungen (siehe <code>src-tauri/src/proxy/token_manager.rs:555-560, 716-719</code>). Das bedeutet:</p><ul><li>Modelle in der Whitelist (wie <code>claude-sonnet-4-5-thinking</code>) werden zur Standard-ID (<code>claude-sonnet-4-5</code>) normalisiert und dann geprüft, ob sie in <code>protected_models</code> enthalten sind</li><li>Wenn die Normalisierung für Modelle außerhalb der Whitelist fehlschlägt, wird auf den ursprünglichen Modellnamen zurückgegriffen, der weiterhin mit <code>protected_models</code> abgeglichen wird</li></ul><p>Mit anderen Worten: Die Quota-Schutzentscheidung gilt für &quot;alle Modellnamen&quot;, nur dass Modelle in der Whitelist zuerst normalisiert werden.</p><h3 id="_3-warum-benotigen-manuelles-geplantes-warmup-dass-der-proxy-lauft" tabindex="-1">3) Warum benötigen manuelles/geplantes Warmup, dass der Proxy läuft? <a class="header-anchor" href="#_3-warum-benotigen-manuelles-geplantes-warmup-dass-der-proxy-lauft" aria-label="Permalink to &quot;3) Warum benötigen manuelles/geplantes Warmup, dass der Proxy läuft?&quot;">​</a></h3><p>Die Warmup-Anfrage erreicht letztendlich den internen Endpunkt des lokalen Proxies: <code>POST /internal/warmup</code> (siehe Routing in <code>src-tauri/src/proxy/server.rs</code> und Implementierung in <code>src-tauri/src/proxy/handlers/warmup.rs</code>). Wenn Sie den Proxy-Dienst nicht gestartet haben, schlägt Warmup fehl.</p><p>Außerdem stammt der Port, den Warmup aufruft, aus der Konfiguration: <code>proxy.port</code> (wenn das Lesen der Konfiguration fehlschlägt, wird auf <code>8045</code> zurückgegriffen, siehe <code>src-tauri/src/modules/quota.rs</code>).</p><h2 id="zusammenfassung-der-lektion" tabindex="-1">Zusammenfassung der Lektion <a class="header-anchor" href="#zusammenfassung-der-lektion" aria-label="Permalink to &quot;Zusammenfassung der Lektion&quot;">​</a></h2><ul><li>Quota Protection sorgt für &quot;Verlustbegrenzung&quot;: Unter dem Schwellenwert wird das Modell in <code>protected_models</code> geschrieben; Anfragen an dieses Modell werden bevorzugt umgangen</li><li>Smart Warmup sorgt für &quot;Selbstprüfung bei voller Quote&quot;: Wird nur bei 100% ausgelöst, alle 10 Minuten gescannt, 4-Stunden-Cooldown</li><li>Beide hängen von der &quot;Quotenaktualisierungs&quot;-Pipeline ab: Erst mit <code>quota.models[]</code> hat das Management eine Grundlage</li></ul><h2 id="vorschau-auf-die-nachste-lektion-1" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion-1" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><p>Quota-Management löst das Problem &quot;wie man stabiler ausgibt&quot;. In der nächsten Lektion wird empfohlen, weiter Proxy Monitor zu lesen, um Anfrageprotokolle, Konto-Treffer und Modell-Zuordnungen in eine wiederholbare Beweiskette zu verwandeln.</p><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie zum Ausklappen, um Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>Quota Protection UI (Schwellenwert, Modellauswahl, mindestens 1 beibehalten)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/QuotaProtection.tsx#L13-L168" target="_blank" rel="noreferrer"><code>src/components/settings/QuotaProtection.tsx</code></a></td><td>13-168</td></tr><tr><td>Smart Warmup UI (Standardauswahl nach Aktivierung, mindestens 1 beibehalten)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/SmartWarmup.tsx#L14-L120" target="_blank" rel="noreferrer"><code>src/components/settings/SmartWarmup.tsx</code></a></td><td>14-120</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table></details>',71)])])}const g=t(a,[["render",o]]);export{m as __pageData,g as default};
